    /// Test CUDA parity (if available)
    #[test]
    fn test_conv3d_parity_cuda() -> anyhow::Result<()> {
        if std::env::var("CANDLE_VIDEO_RUN_CUDA_TESTS").is_err() {
            println!("Skipping CUDA test: CANDLE_VIDEO_RUN_CUDA_TESTS not set");
            return Ok(());
        }

        let ref_path = Path::new("gen_conv3d_ref.safetensors");
        if !ref_path.exists() {
            println!("Skipping test: gen_conv3d_ref.safetensors not found");
            return Ok(());
        }

        let device = Device::new_cuda(0)?;
        let dtype = DType::BF16;
        let tolerance = BF16_TOLERANCE;

        println!("Running Conv3d CUDA parity tests");
        println!(
            "Device: {:?}, Dtype: {:?}, Tolerance: {}",
            device, dtype, tolerance
        );

        let tensors = candle_core::safetensors::load(ref_path, &Device::Cpu)?;
        let test_cases = load_test_cases();

        for test_case in &test_cases {
            match run_parity_test(test_case, &tensors, &device, dtype, tolerance) {
                Ok((_, msg)) => println!("  {}", msg),
                Err(e) => println!("  [ERROR] {} - {}", test_case.name, e),
            }
        }

        Ok(())
    }

    /// Test specific case: pointwise 1x1x1 (should have exact parity)
    #[test]
    fn test_conv3d_parity_pointwise() -> anyhow::Result<()> {
        let ref_path = Path::new("gen_conv3d_ref.safetensors");
        if !ref_path.exists() {
            println!("Skipping test: gen_conv3d_ref.safetensors not found");
            return Ok(());
        }

        let device = Device::Cpu;
        let dtype = DType::F32;
        let tensors = candle_core::safetensors::load(ref_path, &device)?;

        let test_case = TestCase {
            name: "pointwise_1x1x1".to_string(),
            kernel: (1, 1, 1),
            stride: (1, 1, 1),
            padding: (0, 0, 0),
            dilation: (1, 1, 1),
            groups: 1,
            is_causal: false,
        };

        // Pointwise should have very tight tolerance since there's no padding involved
        let (success, msg) = run_parity_test(&test_case, &tensors, &device, dtype, 0.02)?;
        println!("{}", msg);

        // Pointwise convolution should match closely
        assert!(
            success || msg.contains("SKIP"),
            "Pointwise parity failed: {}",
            msg
        );
        Ok(())
    }

